// Helper: get the category for an effect name (returns label, or NULL if no match)
static const char* GetEffectCategoryLabel(const char* name)
{
    if (!name) return NULL;
    // Try specific prefixes first (longer prefixes before shorter)
    for (int c = 0; c < s_effectCategoryCount; ++c)
    {
        const char* pfx = s_effectCategories[c].prefix;
        size_t plen = strlen(pfx);
        bool match = true;
        for (size_t j = 0; j < plen && name[j]; ++j)
        {
            if (name[j] != pfx[j]) { match = false; break; }
        }
        if (match && strlen(name) >= plen) return s_effectCategories[c].label;
    }
    return NULL;
}

// Categorized filterable combo for large lists (e.g., particle effects).
// When search is empty, shows effects grouped by prefix category with collapsible headers.
// When search has text, shows a flat filtered list (same as FilterableCombo).
static bool CategorizedFilterableCombo(const char* label, char* buf, int bufSize,
                                        const char* const* items, int itemCount,
                                        const char* hintText = NULL)
{
    bool changed = false;
    ImGui::PushID(label);

    float inputWidth = ImGui::CalcItemWidth();
    ImGui::SetNextItemWidth(inputWidth);
    if (hintText)
        changed = ImGui::InputTextWithHint(label, hintText, buf, bufSize);
    else
        changed = ImGui::InputText(label, buf, bufSize);

    bool hasFilter = (buf[0] != '\0');
    bool isActive = ImGui::IsItemActive();

    // Count matching items
    int matchCount = 0;
    if (isActive)
    {
        for (int i = 0; i < itemCount; ++i)
        {
            if (hasFilter && !StrContainsCaseInsensitive(items[i], buf)) continue;
            matchCount++;
        }
    }

    if (matchCount > 0 && isActive)
    {
        float maxH = ImGui::GetTextLineHeightWithSpacing() * 30.0f;
        ImGui::SetNextWindowPos(ImVec2(ImGui::GetItemRectMin().x, ImGui::GetItemRectMax().y));
        ImGui::SetNextWindowSize(ImVec2(inputWidth + 80.0f, maxH));
        ImGuiWindowFlags flags = ImGuiWindowFlags_NoTitleBar | ImGuiWindowFlags_NoMove | ImGuiWindowFlags_NoResize
                               | ImGuiWindowFlags_NoSavedSettings | ImGuiWindowFlags_Tooltip;
        if (ImGui::Begin("##catSuggestions", NULL, flags))
        {
            if (hasFilter)
            {
                // Flat filtered list
                for (int i = 0; i < itemCount; ++i)
                {
                    if (!StrContainsCaseInsensitive(items[i], buf)) continue;
                    if (ImGui::Selectable(items[i]))
                    {
                        strncpy_s(buf, bufSize, items[i], _TRUNCATE);
                        changed = true;
                        ImGui::SetWindowFocus(NULL);
                    }
                }
            }
            else
            {
                // Categorized view: group by prefix
                // Track which items have been shown
                std::vector<bool> shown((size_t)itemCount, false);

                for (int c = 0; c < s_effectCategoryCount; ++c)
                {
                    const char* pfx = s_effectCategories[c].prefix;
                    size_t plen = strlen(pfx);

                    // Count items in this category
                    int catCount = 0;
                    for (int i = 0; i < itemCount; ++i)
                    {
                        if (shown[i]) continue;
                        if (!items[i]) continue;
                        bool pfxMatch = true;
                        for (size_t j = 0; j < plen && items[i][j]; ++j)
                        {
                            if (items[i][j] != pfx[j]) { pfxMatch = false; break; }
                        }
                        if (pfxMatch && strlen(items[i]) >= plen) catCount++;
                    }
                    if (catCount == 0) continue;

                    char catLabel[128];
                    _snprintf_s(catLabel, sizeof(catLabel), _TRUNCATE, "%s (%d)", s_effectCategories[c].label, catCount);

                    if (ImGui::TreeNode(catLabel))
                    {
                        for (int i = 0; i < itemCount; ++i)
                        {
                            if (shown[i]) continue;
                            if (!items[i]) continue;
                            bool pfxMatch = true;
                            for (size_t j = 0; j < plen && items[i][j]; ++j)
                            {
                                if (items[i][j] != pfx[j]) { pfxMatch = false; break; }
                            }
                            if (!pfxMatch || strlen(items[i]) < plen) continue;

                            shown[i] = true;
                            if (ImGui::Selectable(items[i]))
                            {
                                strncpy_s(buf, bufSize, items[i], _TRUNCATE);
                                changed = true;
                                ImGui::SetWindowFocus(NULL);
                            }
                        }
                        ImGui::TreePop();
                    }
                    else
                    {
                        // Mark items as shown even if collapsed
                        for (int i = 0; i < itemCount; ++i)
                        {
                            if (shown[i]) continue;
                            if (!items[i]) continue;
                            bool pfxMatch = true;
                            for (size_t j = 0; j < plen && items[i][j]; ++j)
                            {
                                if (items[i][j] != pfx[j]) { pfxMatch = false; break; }
                            }
                            if (pfxMatch && strlen(items[i]) >= plen) shown[i] = true;
                        }
                    }
                }

                // Uncategorized items
                int uncatCount = 0;
                for (int i = 0; i < itemCount; ++i)
                    if (!shown[i] && items[i]) uncatCount++;
                if (uncatCount > 0)
                {
                    char uncatLabel[64];
                    _snprintf_s(uncatLabel, sizeof(uncatLabel), _TRUNCATE, "Other (%d)", uncatCount);
                    if (ImGui::TreeNode(uncatLabel))
                    {
                        for (int i = 0; i < itemCount; ++i)
                        {
                            if (shown[i] || !items[i]) continue;
                            if (ImGui::Selectable(items[i]))
                            {
                                strncpy_s(buf, bufSize, items[i], _TRUNCATE);
                                changed = true;
                                ImGui::SetWindowFocus(NULL);
                            }
                        }
                        ImGui::TreePop();
                    }
                }
            }
        }
        ImGui::End();
    }

    ImGui::PopID();
    return changed;
}

static bool FilterableCombo(const char* label, char* buf, int bufSize,
                            const char* const* items, int itemCount,
                            const char* hintText = NULL)
{
    bool changed = false;
    ImGui::PushID(label);

    // Text input with hint
    float inputWidth = ImGui::CalcItemWidth();
    ImGui::SetNextItemWidth(inputWidth);
    if (hintText)
        changed = ImGui::InputTextWithHint(label, hintText, buf, bufSize);
    else
        changed = ImGui::InputText(label, buf, bufSize);

    // Count matching items
    int matchCount = 0;
    for (int i = 0; i < itemCount; ++i)
    {
        if (StrContainsCaseInsensitive(items[i], buf))
            matchCount++;
    }

    // Show filtered suggestion list below the input
    if (matchCount > 0 && ImGui::IsItemActive())
    {
        // Use a child window to show suggestions
        ImGui::SetNextWindowPos(ImVec2(ImGui::GetItemRectMin().x, ImGui::GetItemRectMax().y));
        ImGui::SetNextWindowSize(ImVec2(inputWidth, ImGui::GetTextLineHeightWithSpacing() * ((matchCount < 10) ? (float)(matchCount + 0.5f) : 10.5f)));
        ImGuiWindowFlags flags = ImGuiWindowFlags_NoTitleBar | ImGuiWindowFlags_NoMove | ImGuiWindowFlags_NoResize
                               | ImGuiWindowFlags_NoSavedSettings | ImGuiWindowFlags_Tooltip;
        if (ImGui::Begin("##suggestions", NULL, flags))
        {
            for (int i = 0; i < itemCount; ++i)
            {
                if (!StrContainsCaseInsensitive(items[i], buf))
                    continue;
                if (items[i][0] == '\0')
                {
                    if (ImGui::Selectable("(none / empty)"))
                    {
                        buf[0] = '\0';
                        changed = true;
                        ImGui::SetWindowFocus(NULL);
                    }
                }
                else if (ImGui::Selectable(items[i]))
                {
                    strncpy_s(buf, bufSize, items[i], _TRUNCATE);
                    changed = true;
                    ImGui::SetWindowFocus(NULL);
                }
            }
        }
        ImGui::End();
    }

    ImGui::PopID();
    return changed;
}

// =========================================================================
// GLOBAL STATE — THE GRAVEYARD OF GOOD INTENTIONS
//
// 30+ static bools, each one a toggle for a different panel or feature.
// Every single one starts as "I'll just add ONE more bool" and ends
// with me scrolling through 25 g_show* variables at 3 AM trying to
// remember which one controls the fucking timeline panel. This is
// what happens when you don't use a proper state management system.
