static bool ContainsNoCase(const char* text, const char* sub)
{
    if (!sub || !sub[0]) return true;
    if (!text || !text[0]) return false;
    size_t nlen = strlen(sub);
    for (const char* p = text; *p; ++p)
    {
        size_t i = 0;
        for (; i < nlen && p[i]; ++i)
        {
            if (tolower((unsigned char)p[i]) != tolower((unsigned char)sub[i]))
                break;
        }
        if (i == nlen)
            return true;
    }
    return false;
}

// ============================================================================
// LUA TREE VIEW — A HAND-WRITTEN RECURSIVE DESCENT LUA PARSER BECAUSE WHY NOT
//
// I wrote a Lua parser. By hand. In C++. Inside a UI DLL. For a game engine
// reverse-engineering tool. It handles tables, nested tables, strings (single
// and double quoted), numbers, bools, function calls, raw expressions, array
// indices, and comments. It's not a full Lua parser — it's a TABLE parser
// that handles enough syntax to correctly parse Pandemic's animation state
// machine scripts. If you feed it arbitrary Lua code it will probably
// choke, crash, or produce modern art in the tree view.
//
// But for Pandemic's scripts? It works perfectly. Every state. Every
// transition. Every condition. Every blend node. Parsed into an editable
// tree that you can modify in the UI and regenerate back to valid Lua.
// I could have used an existing Lua parser library. I could have embedded
// a Lua interpreter. But those would add dependencies and I am VIOLENTLY
// allergic to dependencies at this point. So I wrote 600 lines of parser
// instead. Because that's a healthy decision. That's a decision made by
// a well-adjusted person who definitely does not need professional help.
// ============================================================================

enum LuaNodeType { LN_TABLE = 0, LN_STRING, LN_NUMBER, LN_BOOL, LN_FUNCALL, LN_RAW };

struct LuaTreeNode {
    char key[128];       // "Idle", "1" (array index), or "" for root
    char value[512];     // leaf value text (empty for tables)
    int  nodeType;       // LuaNodeType
    int  parent;         // index of parent, -1 = root-level
    int  childFirst;     // first child index in array, -1 if leaf
    int  childCount;     // number of direct children
    int  depth;
    bool expanded;       // UI state
};

struct LuaTreeCache {
    std::vector<LuaTreeNode> nodes;
    char*       lastBuffer;
    int         lastBufferLen;
    bool        dirty;           // tree was edited, buffer needs regen
    bool        valid;
};

static LuaTreeCache s_luaTree = { std::vector<LuaTreeNode>(), NULL, 0, false, false };

static void LuaTree_SkipWhitespace(const char*& p) {
    while (*p && (*p == ' ' || *p == '\t' || *p == '\r' || *p == '\n')) ++p;
}

static void LuaTree_SkipLineComment(const char*& p) {
    while (*p && *p != '\n') ++p;
    if (*p == '\n') ++p;
}

static void LuaTree_SkipBlockComment(const char*& p) {
    // skip --[[ ... ]]
    p += 4; // past --[[
    while (*p) {
        if (p[0] == ']' && p[1] == ']') { p += 2; return; }
        ++p;
    }
}

static void LuaTree_SkipWhitespaceAndComments(const char*& p) {
    for (;;) {
        LuaTree_SkipWhitespace(p);
        if (p[0] == '-' && p[1] == '-') {
            if (p[2] == '[' && p[3] == '[') LuaTree_SkipBlockComment(p);
            else LuaTree_SkipLineComment(p);
        } else break;
    }
}

// Read a quoted string, returning content (without quotes). Advances p past closing quote.
static int LuaTree_ReadString(const char*& p, char* out, int outSize) {
    char quote = *p++;
    int len = 0;
    while (*p && *p != quote && len < outSize - 1) {
        if (*p == '\\' && p[1]) { out[len++] = p[1]; p += 2; }
        else { out[len++] = *p++; }
    }
    if (*p == quote) ++p;
    out[len] = '\0';
    return len;
}

// Read a "word" (identifier, number, bool, or function call) up to comma/brace/newline
static int LuaTree_ReadValue(const char*& p, char* out, int outSize) {
    int len = 0;
    int parenDepth = 0;
    int braceDepth = 0;
    while (*p && len < outSize - 1) {
        if (*p == '(' ) { parenDepth++; out[len++] = *p++; continue; }
        if (*p == ')' ) { if (parenDepth > 0) parenDepth--; out[len++] = *p++; continue; }
        if (*p == '{' ) { braceDepth++; out[len++] = *p++; continue; }
        if (*p == '}' ) {
            if (braceDepth > 0) { braceDepth--; out[len++] = *p++; continue; }
            break; // end of enclosing table
        }
        if (parenDepth == 0 && braceDepth == 0 && (*p == ',' || *p == '\n' || *p == '\r'))
            break;
        out[len++] = *p++;
    }
    // trim trailing whitespace
    while (len > 0 && (out[len-1] == ' ' || out[len-1] == '\t')) --len;
    out[len] = '\0';
    return len;
}

// Classify a value string
static int LuaTree_ClassifyValue(const char* val) {
    if (!val[0]) return LN_RAW;
    if (strcmp(val, "true") == 0 || strcmp(val, "false") == 0) return LN_BOOL;
    // number: starts with digit or minus
    if ((val[0] >= '0' && val[0] <= '9') || (val[0] == '-' && val[1] >= '0' && val[1] <= '9'))
        return LN_NUMBER;
    // function call: contains '('
    for (const char* c = val; *c; ++c) if (*c == '(') return LN_FUNCALL;
    return LN_RAW;
}

// Forward declaration
static void LuaTree_ParseTableContents(const char*& p, int parentIdx, int depth);

// Parse a { ... } table body, creating child nodes under parentIdx
static void LuaTree_ParseTableContents(const char*& p, int parentIdx, int depth)
{
    int arrayIndex = 1;
    int childStart = (int)s_luaTree.nodes.size();

    for (;;) {
        LuaTree_SkipWhitespaceAndComments(p);
        if (!*p || *p == '}') break;

        // Try: Key = Value
        const char* saved = p;
        char key[128] = "";
        bool isKeyValue = false;

        // Check for identifier = ...
        if ((*p >= 'A' && *p <= 'Z') || (*p >= 'a' && *p <= 'z') || *p == '_') {
            int ki = 0;
            const char* kp = p;
            while (*kp && ((*kp >= 'A' && *kp <= 'Z') || (*kp >= 'a' && *kp <= 'z') ||
                   (*kp >= '0' && *kp <= '9') || *kp == '_') && ki < 126)
                key[ki++] = *kp++;
            key[ki] = '\0';
            const char* afterKey = kp;
            LuaTree_SkipWhitespace(kp);
            if (*kp == '=') {
                ++kp;
                LuaTree_SkipWhitespace(kp);
                p = kp;
                isKeyValue = true;
            } else {
                // Not a key=value, restore
                p = saved;
                key[0] = '\0';
            }
        }

        if (!isKeyValue) {
            // Array element — use numeric key
            sprintf(key, "%d", arrayIndex++);
        }

        LuaTree_SkipWhitespaceAndComments(p);
        if (!*p) break;

        // Value
        if (*p == '{') {
            // Nested table
            ++p; // skip '{'
            LuaTreeNode node;
            memset(&node, 0, sizeof(node));
            strncpy(node.key, key, 127);
            node.nodeType = LN_TABLE;
            node.parent = parentIdx;
            node.depth = depth;
            node.expanded = (depth < 2);
            node.childFirst = -1;
            node.childCount = 0;
            int nodeIdx = (int)s_luaTree.nodes.size();
            s_luaTree.nodes.push_back(node);
            LuaTree_ParseTableContents(p, nodeIdx, depth + 1);
            LuaTree_SkipWhitespaceAndComments(p);
            if (*p == '}') ++p;
        }
        else if (*p == '"' || *p == '\'') {
            // String value
            char val[512] = "";
            LuaTree_ReadString(p, val, 512);
            LuaTreeNode node;
            memset(&node, 0, sizeof(node));
            strncpy(node.key, key, 127);
            strncpy(node.value, val, 511);
            node.nodeType = LN_STRING;
            node.parent = parentIdx;
            node.depth = depth;
            node.childFirst = -1;
            node.childCount = 0;
            node.expanded = false;
            s_luaTree.nodes.push_back(node);
        }
        else {
            // Number, bool, function call, or raw expression
            char val[512] = "";
            LuaTree_ReadValue(p, val, 512);
            LuaTreeNode node;
            memset(&node, 0, sizeof(node));
            strncpy(node.key, key, 127);
            strncpy(node.value, val, 511);
            node.nodeType = LuaTree_ClassifyValue(val);
            node.parent = parentIdx;
            node.depth = depth;
            node.childFirst = -1;
            node.childCount = 0;
            node.expanded = false;
            s_luaTree.nodes.push_back(node);
        }

        // Skip comma or semicolon separator
        LuaTree_SkipWhitespaceAndComments(p);
        if (*p == ',' || *p == ';') ++p;
    }

    // Update parent's child info
    if (parentIdx >= 0) {
        s_luaTree.nodes[parentIdx].childFirst = childStart;
        s_luaTree.nodes[parentIdx].childCount = (int)s_luaTree.nodes.size() - childStart;
    }
}

// Top-level parse: handles import("..."), inherit("..."), VarName = { ... }, function defs, etc.
static void LuaTree_Parse(const char* text)
{
    s_luaTree.nodes.clear();
    if (!text || !text[0]) return;

    const char* p = text;
    for (;;) {
        LuaTree_SkipWhitespaceAndComments(p);
        if (!*p) break;

        // Skip lines starting with import/inherit/require
        if (strncmp(p, "import(", 7) == 0 || strncmp(p, "inherit(", 8) == 0 ||
            strncmp(p, "require(", 8) == 0) {
            // Store as a raw node
            char line[512] = "";
            int len = 0;
            while (*p && *p != '\n' && len < 510) line[len++] = *p++;
            line[len] = '\0';
            LuaTreeNode node;
            memset(&node, 0, sizeof(node));
            strncpy(node.key, "import", 127);
            strncpy(node.value, line, 511);
            node.nodeType = LN_FUNCALL;
            node.parent = -1;
            node.depth = 0;
            node.childFirst = -1;
            node.childCount = 0;
            node.expanded = false;
            s_luaTree.nodes.push_back(node);
            continue;
        }

        // Skip function definitions — store as collapsed raw blocks
        if (strncmp(p, "function ", 9) == 0 || strncmp(p, "local function ", 15) == 0) {
            const char* start = p;
            // Find matching 'end'
            int depth = 1;
            // Skip to end of the "function" line
            while (*p && *p != '\n') ++p;
            if (*p) ++p;
            while (*p && depth > 0) {
                LuaTree_SkipWhitespaceAndComments(p);
                if (strncmp(p, "function ", 9) == 0 || strncmp(p, "local function ", 15) == 0) {
                    ++depth;
                    while (*p && *p != '\n') ++p;
                    if (*p) ++p;
                } else if (strncmp(p, "if ", 3) == 0 || strncmp(p, "if(", 3) == 0 ||
                           strncmp(p, "for ", 4) == 0 || strncmp(p, "while ", 6) == 0 ||
                           strncmp(p, "do\n", 3) == 0 || strncmp(p, "do\r", 3) == 0 ||
                           strncmp(p, "do ", 3) == 0) {
                    ++depth;
                    while (*p && *p != '\n') ++p;
                    if (*p) ++p;
                } else if (strncmp(p, "end", 3) == 0 &&
                           (!p[3] || p[3] == '\n' || p[3] == '\r' || p[3] == ' ' || p[3] == ')' || p[3] == ',')) {
                    --depth;
                    p += 3;
                    if (depth == 0) break;
                    while (*p && *p != '\n') ++p;
                    if (*p) ++p;
                } else {
                    while (*p && *p != '\n') ++p;
                    if (*p) ++p;
                }
            }
            // Extract function name from first line
            char funcLine[256] = "";
            int fl = 0;
            const char* fp = start;
            while (*fp && *fp != '\n' && fl < 254) funcLine[fl++] = *fp++;
            funcLine[fl] = '\0';

            LuaTreeNode node;
            memset(&node, 0, sizeof(node));
            strncpy(node.key, "function", 127);
            strncpy(node.value, funcLine, 511);
            node.nodeType = LN_FUNCALL;
            node.parent = -1;
            node.depth = 0;
            node.childFirst = -1;
            node.childCount = 0;
            node.expanded = false;
            s_luaTree.nodes.push_back(node);
            continue;
        }

        // Try: Identifier = { ... } (top-level table assignment)
        if ((*p >= 'A' && *p <= 'Z') || (*p >= 'a' && *p <= 'z') || *p == '_') {
            char key[128] = "";
            int ki = 0;
            const char* saved = p;
            while (*p && ((*p >= 'A' && *p <= 'Z') || (*p >= 'a' && *p <= 'z') ||
                   (*p >= '0' && *p <= '9') || *p == '_') && ki < 126)
                key[ki++] = *p++;
            key[ki] = '\0';
            LuaTree_SkipWhitespace(p);
            if (*p == '=') {
                ++p;
                LuaTree_SkipWhitespace(p);
                if (*p == '{') {
                    ++p;
                    LuaTreeNode node;
                    memset(&node, 0, sizeof(node));
                    strncpy(node.key, key, 127);
                    node.nodeType = LN_TABLE;
                    node.parent = -1;
                    node.depth = 0;
                    node.expanded = true;
                    node.childFirst = -1;
                    node.childCount = 0;
                    int nodeIdx = (int)s_luaTree.nodes.size();
                    s_luaTree.nodes.push_back(node);
                    LuaTree_ParseTableContents(p, nodeIdx, 1);
                    LuaTree_SkipWhitespaceAndComments(p);
                    if (*p == '}') ++p;
                } else {
                    // Simple assignment: VarName = value
                    char val[512] = "";
                    if (*p == '"' || *p == '\'') {
                        LuaTree_ReadString(p, val, 512);
                        LuaTreeNode node;
                        memset(&node, 0, sizeof(node));
                        strncpy(node.key, key, 127);
                        strncpy(node.value, val, 511);
                        node.nodeType = LN_STRING;
                        node.parent = -1;
                        node.depth = 0;
                        node.childFirst = -1;
                        node.childCount = 0;
                        node.expanded = false;
                        s_luaTree.nodes.push_back(node);
                    } else {
                        LuaTree_ReadValue(p, val, 512);
                        LuaTreeNode node;
                        memset(&node, 0, sizeof(node));
                        strncpy(node.key, key, 127);
                        strncpy(node.value, val, 511);
                        node.nodeType = LuaTree_ClassifyValue(val);
                        node.parent = -1;
                        node.depth = 0;
                        node.childFirst = -1;
                        node.childCount = 0;
                        node.expanded = false;
                        s_luaTree.nodes.push_back(node);
                    }
                }
            } else {
                // bare identifier or something else — skip line
                p = saved;
                while (*p && *p != '\n') ++p;
                if (*p) ++p;
            }
            continue;
        }

        // Skip anything else (bare lines, stray tokens)
        while (*p && *p != '\n') ++p;
        if (*p) ++p;
    }
}

// Regenerate Lua source text from tree
static void LuaTree_WriteNode(const LuaTreeNode& node, int indent, char*& out, char* outEnd)
{
    char indentBuf[64] = "";
    int ilen = indent * 2;
    if (ilen > 62) ilen = 62;
    for (int i = 0; i < ilen; ++i) indentBuf[i] = ' ';
    indentBuf[ilen] = '\0';

    if (node.parent == -1 && node.nodeType == LN_FUNCALL) {
        // Import/inherit/function — write raw
        int n = _snprintf(out, outEnd - out, "%s\n", node.value);
        if (n > 0) out += n;
        return;
    }

    // Indentation
    int n = _snprintf(out, outEnd - out, "%s", indentBuf);
    if (n > 0) out += n;

    // Key
    bool isArrayKey = (node.key[0] >= '0' && node.key[0] <= '9');
    if (!isArrayKey && node.key[0]) {
        n = _snprintf(out, outEnd - out, "%s = ", node.key);
        if (n > 0) out += n;
    }

    if (node.nodeType == LN_TABLE) {
        n = _snprintf(out, outEnd - out, "{\n");
        if (n > 0) out += n;
        // Children will be written by caller
    } else if (node.nodeType == LN_STRING) {
        n = _snprintf(out, outEnd - out, "\"%s\"", node.value);
        if (n > 0) out += n;
    } else {
        n = _snprintf(out, outEnd - out, "%s", node.value);
        if (n > 0) out += n;
    }
}

static void LuaTree_Regenerate(char* buffer, int bufferSize)
{
    if (s_luaTree.nodes.empty()) return;
    char* out = buffer;
    char* outEnd = buffer + bufferSize - 1;

    // Recursive write
    struct WriteCtx {
        static void WriteChildren(int parentIdx, int indent, char*& out, char* outEnd) {
            LuaTreeNode& par = s_luaTree.nodes[parentIdx];
            for (int c = 0; c < par.childCount && par.childFirst >= 0; ++c) {
                int ci = par.childFirst + c;
                if (ci >= (int)s_luaTree.nodes.size()) break;
                LuaTreeNode& child = s_luaTree.nodes[ci];
                LuaTree_WriteNode(child, indent, out, outEnd);
                if (child.nodeType == LN_TABLE) {
                    WriteChildren(ci, indent + 1, out, outEnd);
                    // Close brace
                    char indentBuf[64] = "";
                    int ilen = indent * 2;
                    if (ilen > 62) ilen = 62;
                    for (int i = 0; i < ilen; ++i) indentBuf[i] = ' ';
                    indentBuf[ilen] = '\0';
                    int n = _snprintf(out, outEnd - out, "%s}", indentBuf);
                    if (n > 0) out += n;
                }
                // Comma/newline
                if (child.parent >= 0) {
                    int n = _snprintf(out, outEnd - out, ",\n");
                    if (n > 0) out += n;
                } else {
                    int n = _snprintf(out, outEnd - out, "\n");
                    if (n > 0) out += n;
                }
            }
        }
    };

    // Write root-level nodes
    for (int i = 0; i < (int)s_luaTree.nodes.size(); ++i) {
        LuaTreeNode& node = s_luaTree.nodes[i];
        if (node.parent != -1) continue; // only root-level
        LuaTree_WriteNode(node, 0, out, outEnd);
        if (node.nodeType == LN_TABLE) {
            WriteCtx::WriteChildren(i, 1, out, outEnd);
            int n = _snprintf(out, outEnd - out, "}\n");
            if (n > 0) out += n;
        } else if (node.nodeType != LN_FUNCALL) {
            int n = _snprintf(out, outEnd - out, "\n");
            if (n > 0) out += n;
        }
    }

    *out = '\0';
}

static void LuaTree_RenderNode(int nodeIdx, ImGuiGlueFrameArgs* out);

static void LuaTree_RenderNode(int nodeIdx, ImGuiGlueFrameArgs* out)
{
    (void)out;
    if (nodeIdx < 0 || nodeIdx >= (int)s_luaTree.nodes.size()) return;
    LuaTreeNode& node = s_luaTree.nodes[nodeIdx];

    ImGui::PushID(nodeIdx);

    if (node.nodeType == LN_TABLE) {
        // Color tables distinctly
        ImGui::PushStyleColor(ImGuiCol_Text, ImVec4(0.6f, 0.9f, 1.0f, 1.0f));
        bool isArrayKey = (node.key[0] >= '0' && node.key[0] <= '9');
        char label[192];
        if (isArrayKey)
            _snprintf(label, sizeof(label), "[%s] {%d}##n%d", node.key, node.childCount, nodeIdx);
        else
            _snprintf(label, sizeof(label), "%s {%d}##n%d", node.key, node.childCount, nodeIdx);

        ImGuiTreeNodeFlags flags = ImGuiTreeNodeFlags_OpenOnArrow;
        if (node.expanded) flags |= ImGuiTreeNodeFlags_DefaultOpen;
        bool open = ImGui::TreeNodeEx(label, flags);
        ImGui::PopStyleColor();

        if (open != node.expanded) node.expanded = open;
        if (open) {
            for (int c = 0; c < node.childCount && node.childFirst >= 0; ++c) {
                int ci = node.childFirst + c;
                if (ci < (int)s_luaTree.nodes.size())
                    LuaTree_RenderNode(ci, out);
            }
            ImGui::TreePop();
        }
    }
    else if (node.nodeType == LN_FUNCALL && node.parent == -1) {
        // Import/function line — show as disabled text
        ImGui::TextDisabled("%s", node.value);
    }
    else {
        // Leaf node — editable
        bool isArrayKey = (node.key[0] >= '0' && node.key[0] <= '9');

        // Type-colored label
        ImVec4 typeCol(0.7f, 0.7f, 0.7f, 1.0f);
        const char* typeTag = "";
        switch (node.nodeType) {
        case LN_STRING:  typeCol = ImVec4(0.4f, 1.0f, 0.4f, 1.0f); typeTag = "S"; break;
        case LN_NUMBER:  typeCol = ImVec4(0.4f, 0.8f, 1.0f, 1.0f); typeTag = "N"; break;
        case LN_BOOL:    typeCol = ImVec4(1.0f, 0.8f, 0.3f, 1.0f); typeTag = "B"; break;
        case LN_FUNCALL: typeCol = ImVec4(0.8f, 0.5f, 1.0f, 1.0f); typeTag = "F"; break;
        default:         typeCol = ImVec4(0.7f, 0.7f, 0.7f, 1.0f); typeTag = "?"; break;
        }

        // Key label
        if (isArrayKey)
            ImGui::TextDisabled("[%s]", node.key);
        else
            ImGui::Text("%s", node.key);
        ImGui::SameLine();
        ImGui::TextColored(typeCol, "(%s)", typeTag);
        ImGui::SameLine();

        if (node.nodeType == LN_BOOL) {
            bool bval = (strcmp(node.value, "true") == 0);
            if (ImGui::Checkbox("##val", &bval)) {
                strncpy(node.value, bval ? "true" : "false", 511);
                s_luaTree.dirty = true;
            }
        }
        else if (node.nodeType == LN_NUMBER) {
            // Show as drag for numbers
            float fval = (float)atof(node.value);
            ImGui::SetNextItemWidth(120.0f);
            if (ImGui::DragFloat("##val", &fval, 0.1f, 0.0f, 0.0f, "%.4g")) {
                _snprintf(node.value, 511, "%g", fval);
                s_luaTree.dirty = true;
            }
        }
        else if (node.nodeType == LN_FUNCALL) {
            // Function calls: show as disabled text (not safely editable inline)
            ImGui::TextDisabled("%s", node.value);
        }
        else {
            // String or raw — editable text
            ImGui::SetNextItemWidth(-1.0f);
            if (ImGui::InputText("##val", node.value, sizeof(node.value))) {
                s_luaTree.dirty = true;
            }
        }
    }

    ImGui::PopID();
}

// Main tree view render function — call this instead of InputTextMultiline
static void LuaTree_RenderTreeView(ImGuiGlueFrameArgs* out, char* buffer, int bufferSize)
{
    if (!buffer || bufferSize <= 0) {
        ImGui::TextDisabled("No source loaded.");
        return;
    }

    // Re-parse if buffer changed (pointer or content)
    int bufLen = (int)strlen(buffer);
    if (buffer != s_luaTree.lastBuffer || bufLen != s_luaTree.lastBufferLen || !s_luaTree.valid) {
        LuaTree_Parse(buffer);
        s_luaTree.lastBuffer = buffer;
        s_luaTree.lastBufferLen = bufLen;
        s_luaTree.valid = true;
        s_luaTree.dirty = false;
    }

    if (s_luaTree.nodes.empty()) {
        ImGui::TextDisabled("Empty or unparseable Lua file.");
        return;
    }

    // Dirty indicator + apply button
    if (s_luaTree.dirty) {
        ImGui::TextColored(ImVec4(1.0f, 0.6f, 0.2f, 1.0f), "* Modified (unsaved)");
        ImGui::SameLine();
        if (ImGui::SmallButton("Apply to Source")) {
            LuaTree_Regenerate(buffer, bufferSize);
            s_luaTree.lastBufferLen = (int)strlen(buffer);
            s_luaTree.dirty = false;
        }
    }

    ImGui::TextDisabled("%d nodes parsed", (int)s_luaTree.nodes.size());

    // Collapse/Expand all buttons
    if (ImGui::SmallButton("Expand All"))
    {
        for (size_t ni = 0; ni < s_luaTree.nodes.size(); ++ni)
            s_luaTree.nodes[ni].expanded = true;
    }
    ImGui::SameLine();
    if (ImGui::SmallButton("Collapse All"))
    {
        for (size_t ni = 0; ni < s_luaTree.nodes.size(); ++ni)
            s_luaTree.nodes[ni].expanded = false;
    }

    // Scrollable child for tree
    ImGui::BeginChild("LuaTreeChild", ImVec2(0, 300), true);
    for (int i = 0; i < (int)s_luaTree.nodes.size(); ++i) {
        if (s_luaTree.nodes[i].parent == -1)
            LuaTree_RenderNode(i, out);
    }
    ImGui::EndChild();
}

// ============================================================================
// ====== LUA EDITOR HELPERS (file-scope) ======
// ============================================================================

// --- Recent files list ---
static std::vector<std::string> s_luaRecentFiles;
static void LuaRecent_Push(const char* path) {
    if (!path || !path[0]) return;
    std::string p(path);
    for (size_t i = 0; i < s_luaRecentFiles.size(); ++i) {
        if (s_luaRecentFiles[i] == p) { s_luaRecentFiles.erase(s_luaRecentFiles.begin() + i); break; }
    }
    s_luaRecentFiles.insert(s_luaRecentFiles.begin(), p);
    if (s_luaRecentFiles.size() > 15) s_luaRecentFiles.resize(15);
}

// --- Pinned/favorite files ---
static std::vector<std::string> s_luaPinnedFiles;
static bool LuaPin_Has(const char* path) {
    for (size_t i = 0; i < s_luaPinnedFiles.size(); ++i)
        if (s_luaPinnedFiles[i] == std::string(path)) return true;
    return false;
}
static void LuaPin_Toggle(const char* path) {
    std::string p(path);
    for (size_t i = 0; i < s_luaPinnedFiles.size(); ++i) {
        if (s_luaPinnedFiles[i] == p) { s_luaPinnedFiles.erase(s_luaPinnedFiles.begin() + i); return; }
    }
    s_luaPinnedFiles.push_back(p);
}

// --- Lua keyword detection for syntax highlighting ---
static bool IsLuaKeyword(const char* word, int len) {
    static const char* kw[] = {
        "and","break","do","else","elseif","end","false","for","function",
        "if","in","local","nil","not","or","repeat","return","then","true",
        "until","while","import","inherit","AnimTable","AnimTableName",
        "AnimTableNames","AnimTableUsed", NULL
    };
    for (int i = 0; kw[i]; ++i) {
        int kl = (int)strlen(kw[i]);
        if (kl == len && strncmp(word, kw[i], len) == 0) return true;
    }
    return false;
}

// --- Syntax-highlighted Lua source renderer (read-only view with line numbers) ---
static void LuaSyntax_Render(const char* text, int textLen, float availH,
                              const char* searchStr, int searchLen,
                              int* searchMatchCount, int searchJumpTo,
                              ImGuiGlueFrameArgs* outArgs, const char* currentPath) {
    if (!text || textLen <= 0) { ImGui::TextDisabled("(empty)"); return; }

    const ImU32 colKeyword  = IM_COL32(200, 130, 255, 255);
    const ImU32 colString   = IM_COL32(100, 220, 100, 255);
    const ImU32 colComment  = IM_COL32(110, 110, 110, 255);
    const ImU32 colNumber   = IM_COL32(100, 200, 255, 255);
    const ImU32 colNormal   = IM_COL32(220, 220, 220, 255);
    const ImU32 colLineNum  = IM_COL32(100, 100, 100, 255);
    const ImU32 colImport   = IM_COL32(140, 200, 255, 255);
    const ImU32 colSearchBg = IM_COL32(180, 140, 40, 100);

    ImGui::BeginChild("##lua_syntax_view", ImVec2(-1.0f, availH), true,
                      ImGuiWindowFlags_HorizontalScrollbar);
    ImDrawList* dl = ImGui::GetWindowDrawList();
    ImVec2 cursorStart = ImGui::GetCursorScreenPos();
    float lineH = ImGui::GetTextLineHeightWithSpacing();
    float charW = ImGui::CalcTextSize("A").x;
    float lineNumW = charW * 5.0f;

    int lineCount = 1;
    for (int i = 0; i < textLen; ++i)
        if (text[i] == '\n') lineCount++;

    ImGui::Dummy(ImVec2(lineNumW + charW * 120.0f, lineH * lineCount));

    float scrollY = ImGui::GetScrollY();
    int firstVisible = (int)(scrollY / lineH);
    int visibleLines = (int)(availH / lineH) + 2;
    if (firstVisible < 0) firstVisible = 0;

    const char* p = text;
    int curLine = 0;
    while (curLine < firstVisible && *p) {
        if (*p == '\n') curLine++;
        ++p;
    }

    int matchIdx = 0;
    if (searchMatchCount) *searchMatchCount = 0;

    for (int vl = 0; vl < visibleLines + 1 && *p; ++vl) {
        int lineIdx = firstVisible + vl;
        float yPos = cursorStart.y + lineIdx * lineH - scrollY;
        float xBase = cursorStart.x;

        char lnBuf[16];
        sprintf_s(lnBuf, sizeof(lnBuf), "%4d", lineIdx + 1);
        dl->AddText(ImVec2(xBase, yPos), colLineNum, lnBuf);

        float x = xBase + lineNumW;
        const char* lineStart = p;
        const char* lineEnd = p;
        while (*lineEnd && *lineEnd != '\n') ++lineEnd;

        const char* lp = lineStart;
        while (lp < lineEnd) {
            if (lp + 1 < lineEnd && lp[0] == '-' && lp[1] == '-') {
                dl->AddText(ImVec2(x, yPos), colComment, lp, lineEnd);
                x += charW * (lineEnd - lp);
                lp = lineEnd;
                break;
            }
            if (*lp == '"' || *lp == '\'') {
                char q = *lp;
                const char* sStart = lp;
                ++lp;
                while (lp < lineEnd && *lp != q) {
                    if (*lp == '\\') ++lp;
                    ++lp;
                }
                if (lp < lineEnd) ++lp;
                dl->AddText(ImVec2(x, yPos), colString, sStart, lp);

                if (outArgs && currentPath) {
                    const char* checkBack = sStart;
                    while (checkBack > lineStart && *(checkBack-1) == ' ') --checkBack;
                    if (checkBack > lineStart && *(checkBack-1) == '(') {
                        --checkBack;
                        bool isImport = (checkBack - lineStart >= 6 && strncmp(checkBack - 6, "import", 6) == 0);
                        bool isInherit = (checkBack - lineStart >= 7 && strncmp(checkBack - 7, "inherit", 7) == 0);
                        if (isImport || isInherit) {
                            float linkX = x;
                            float linkW = charW * (lp - sStart);
                            ImVec2 linkMin(linkX, yPos);
                            ImVec2 linkMax(linkX + linkW, yPos + lineH);
                            dl->AddLine(ImVec2(linkMin.x, linkMax.y - 2), ImVec2(linkMax.x, linkMax.y - 2),
                                        colImport, 1.0f);
                            ImVec2 mp = ImGui::GetMousePos();
                            if (mp.x >= linkMin.x && mp.x <= linkMax.x &&
                                mp.y >= linkMin.y && mp.y <= linkMax.y) {
                                ImGui::SetMouseCursor(ImGuiMouseCursor_Hand);
                                std::string importName(sStart + 1, lp - sStart - 2);
                                ImGui::SetTooltip("Click to open: %s", importName.c_str());
                                if (ImGui::IsMouseClicked(0)) {
                                    ImGuiGlueFrameArgs* mout = const_cast<ImGuiGlueFrameArgs*>(outArgs);
                                    mout->requestOpenLuaEditor = 1;
                                    std::string dir(currentPath);
                                    size_t sl = dir.find_last_of("\\/");
                                    if (sl != std::string::npos) dir = dir.substr(0, sl);
                                    std::string resolved = dir + "\\" + importName + ".lua";
                                    strncpy_s(mout->requestedLuaEditorPath, sizeof(mout->requestedLuaEditorPath),
                                              resolved.c_str(), _TRUNCATE);
                                }
                            }
                        }
                    }
                }
                x += charW * (lp - sStart);
                continue;
            }
            if ((*lp >= '0' && *lp <= '9') || (*lp == '-' && lp + 1 < lineEnd && lp[1] >= '0' && lp[1] <= '9')) {
                const char* nStart = lp;
                if (*lp == '-') ++lp;
                while (lp < lineEnd && ((*lp >= '0' && *lp <= '9') || *lp == '.')) ++lp;
                dl->AddText(ImVec2(x, yPos), colNumber, nStart, lp);
                x += charW * (lp - nStart);
                continue;
            }
            if ((*lp >= 'a' && *lp <= 'z') || (*lp >= 'A' && *lp <= 'Z') || *lp == '_') {
                const char* wStart = lp;
                while (lp < lineEnd && ((*lp >= 'a' && *lp <= 'z') || (*lp >= 'A' && *lp <= 'Z') ||
                       (*lp >= '0' && *lp <= '9') || *lp == '_')) ++lp;
                int wLen = (int)(lp - wStart);
                ImU32 wCol = IsLuaKeyword(wStart, wLen) ? colKeyword : colNormal;
                dl->AddText(ImVec2(x, yPos), wCol, wStart, lp);
                x += charW * wLen;
                continue;
            }
            dl->AddText(ImVec2(x, yPos), colNormal, lp, lp + 1);
            x += charW;
            ++lp;
        }

        if (searchStr && searchLen > 0) {
            const char* sp = lineStart;
            while (sp + searchLen <= lineEnd) {
                bool match = true;
                for (int si = 0; si < searchLen; ++si) {
                    char a = sp[si], b = searchStr[si];
                    if (a >= 'A' && a <= 'Z') a += 32;
                    if (b >= 'A' && b <= 'Z') b += 32;
                    if (a != b) { match = false; break; }
                }
                if (match) {
                    float hlX = xBase + lineNumW + charW * (sp - lineStart);
                    float hlW = charW * searchLen;
                    dl->AddRectFilled(ImVec2(hlX, yPos), ImVec2(hlX + hlW, yPos + lineH), colSearchBg);
                    if (searchMatchCount) (*searchMatchCount)++;
                    matchIdx++;
                    if (searchJumpTo >= 0 && matchIdx == searchJumpTo + 1) {
                        ImGui::SetScrollY(lineIdx * lineH);
                    }
                    sp += searchLen;
                } else {
                    ++sp;
                }
            }
        }

        p = lineEnd;
        if (*p == '\n') ++p;
    }

    ImGui::EndChild();
}

