static void DrawViewportImageOpaqueCallback(const ImDrawList* parent_list, const ImDrawCmd* cmd)
{
    (void)parent_list;
    (void)cmd;
    if (!g_device)
        return;

    // The viewport render-target often contains arbitrary/meaningful alpha from game textures.
    // If we draw it with ImGui's normal alpha blending, models can appear gray/dithered.
    // Force the viewport image to render opaquely (we reset state right after the image).
    g_device->SetRenderState(D3DRS_ALPHABLENDENABLE, FALSE);
    g_device->SetRenderState(D3DRS_SEPARATEALPHABLENDENABLE, FALSE);
}

