                if (!tn) return IM_COL32(180, 180, 180, 255);
                if (strstr(tn,"Prop"))      return IM_COL32(100, 180, 100, 255);
                if (strstr(tn,"Sound"))     return IM_COL32(100, 150, 220, 255);
                if (strstr(tn,"logic"))     return IM_COL32(220, 150, 100, 255);
                if (strstr(tn,"Capture"))   return IM_COL32(200, 100, 200, 255);
                if (strstr(tn,"trigger"))   return IM_COL32(180, 180, 180, 255);
                if (strstr(tn,"Output"))    return IM_COL32(200, 100, 80, 255);
                if (strstr(tn,"Objective")) return IM_COL32(180, 180, 180, 255);
                if (strstr(tn,"MetaReward"))return IM_COL32(180, 180, 180, 255);
                if (strstr(tn,"AIGoal"))    return IM_COL32(255, 200, 100, 255);
                if (strstr(tn,"text"))      return IM_COL32(180, 180, 180, 255);
                if (strstr(tn,"camera") || strstr(tn,"Camera") || strstr(tn,"Cam"))
                                            return IM_COL32(180, 180, 180, 255);
                if (strstr(tn,"Kill") || strstr(tn,"kill")) return IM_COL32(255, 80, 80, 255);
